// // This module designs a 4-bit down-counter that decrements its count on each rising edge of the clock (CLK). When the reset (RST) signal is asserted, the counter resets its value to zero. The current counter value is output through a 4-bit wide signal (Q).
module top_module(
    input CLK,
    input RST,
    output [3:0] Q
);reg [3:0] count;

always @(posedge CLK) begin
    if(RST) begin
        count <= 0;
    end
    else begin
        count <= count + 1;
    end
end

assign Q = count;

endmodule
